import React from 'react';
import {View, Text, TouchableOpacity, StyleSheet} from 'react-native';

export default function WelcomeScreen({navigation}){
  return (
    <View style={styles.centered}>
      <Text style={styles.logo}>RightHand</Text>
      <Text style={styles.tag}>Your money’s right hand.</Text>
      <TouchableOpacity style={styles.primaryButton} onPress={()=>navigation.navigate('Signup')}><Text style={styles.btnText}>Get Started</Text></TouchableOpacity>
      <TouchableOpacity style={styles.ghostButton} onPress={()=>navigation.replace('Main')}><Text style={styles.link}>Log In</Text></TouchableOpacity>
    </View>
  );
}

const styles = StyleSheet.create({
  centered:{flex:1,justifyContent:'center',alignItems:'center',padding:24},
  logo:{fontSize:36,fontWeight:'800'},
  tag:{marginTop:8,color:'#666'},
  primaryButton:{backgroundColor:'#0a84ff',padding:12,paddingHorizontal:24,borderRadius:8,marginTop:16},
  ghostButton:{marginTop:8,alignItems:'center'},
  btnText:{color:'#fff',fontWeight:'700'},
  link:{color:'#0a84ff'}
});
